var body = $input.first().json.body || $input.first().json;
var ticker = body.ticker || body.symbol || "UNKNOWN";
var rawAction = body.action || (body.strategy && body.strategy.action) || "info";
var action = rawAction.toLowerCase();
var price = parseFloat(body.price || body.close || 0);
var strategy = body.strategy_name || body.alert_name || body.strategy || "manual";
if (typeof strategy !== "string") strategy = JSON.stringify(strategy);
var quantity = parseFloat(body.quantity || body.contracts || body.size || 0) || null;
var sl = body.sl ? parseFloat(body.sl) : null;
var tp = body.tp ? parseFloat(body.tp) : null;
var now = new Date().toISOString();

var direction = null;
var normalizedAction = "info";
if (action === "buy" || action === "long") {
  normalizedAction = "open";
  direction = "long";
} else if (action === "sell" || action === "short") {
  normalizedAction = "open";
  direction = "short";
} else if (action === "exit" || action === "close") {
  normalizedAction = "close";
}

return [{json: {
  ticker: ticker.toUpperCase(),
  action: normalizedAction,
  direction: direction,
  price: price,
  quantity: quantity,
  stop_loss: sl,
  take_profit: tp,
  strategy: strategy,
  raw_payload: body,
  received_at: now
}}];

